import { describe, it, expect } from "vitest";
import { extractPdfText } from "../lib/ingest.js";

/**
 * Minimal valid PDF containing "Milchleistung 1234", generated by fpdf2.
 * Stored as base64 so no binary fixture file is needed.
 */
const FIXTURE_PDF_B64 =
  "";

describe("extractPdfText (production implementation from ingest.ts)", () => {
  it("gibt einen nicht-leeren String aus einem echten PDF-Buffer zurück", async () => {
    const buf = Buffer.from(FIXTURE_PDF_B64, "base64");
    const text = await extractPdfText(buf);
    expect(text.length).toBeGreaterThan(0);
  });

  it("enthält den bekannten Text aus der Fixture-PDF", async () => {
    const buf = Buffer.from(FIXTURE_PDF_B64, "base64");
    const text = await extractPdfText(buf);
    expect(text).toContain("Milchleistung");
    expect(text).toContain("1234");
  });

  it("wirft bei einem ungültigen PDF-Buffer einen Fehler", async () => {
    const garbage = Buffer.from("this is not a pdf");
    await expect(extractPdfText(garbage)).rejects.toThrow();
  });
});
